/** Thrown when the API returns a non-2xx response. `body` is the parsed error. */
export class UmbralError extends Error {
  constructor(status, body) {
    super(`umbral: request failed with status ${status}`);
    this.name = "UmbralError";
    this.status = status;
    this.body = body;
  }
}

